import type { CategoryId } from "./categories";

export type Points = 200 | 400 | 600;

export interface Question {
  id: string;
  text: string;
  answer: string;
  image?: string;
  audio?: string;
  answerImage?: string;
  dual?: boolean;
  correctSide?: 'left' | 'right';
  grayscale?: boolean;

}

export type CategoryBank = Record<Points, Question[]>;
export type QuestionsDB = Record<CategoryId, CategoryBank>;

export function chem(formula: string): string {
  return formula
    .replace(/([A-Za-z\)])(\d+)/g, '$1<sub>$2</sub>')
    .replace(/([+-])/g, '<sup>$1</sup>');
}

const mk = (id: string, text: string, answer: string, extra?: Partial<Question>): Question =>
  ({ id, text, answer, ...extra });

